import{_ as t,o as a,c as o,ag as d}from"./chunks/framework.BZohXCq9.js";const p=JSON.parse('{"title":"Visual — Variantes y efectos","description":"Configura las variantes de diseño y efectos visuales de cada sección de tu landing","frontmatter":{"title":"Visual — Variantes y efectos","description":"Configura las variantes de diseño y efectos visuales de cada sección de tu landing"},"headers":[],"relativePath":"studio/seccion-visual.md","filePath":"studio/seccion-visual.md"}'),r={name:"studio/seccion-visual.md"};function i(s,e,n,c,l,u){return a(),o("div",null,[...e[0]||(e[0]=[d('<h2 id="¿que-es" tabindex="-1">¿Qué es? <a class="header-anchor" href="#¿que-es" aria-label="Permalink to &quot;¿Qué es?&quot;">​</a></h2><p><strong>Visual</strong> es el tab de tu panel donde configuras cómo se ve cada sección individual de tu landing: qué variante de diseño usar, espaciado, bordes y animaciones.</p><p>Es diferente a <strong>Cómo Se Ve</strong> (que controla los colores). Visual controla la <strong>estructura y estilo</strong> de cada sección.</p><h2 id="¿donde-lo-encuentro" tabindex="-1">¿Dónde lo encuentro? <a class="header-anchor" href="#¿donde-lo-encuentro" aria-label="Permalink to &quot;¿Dónde lo encuentro?&quot;">​</a></h2><p><strong>Tu panel → Visual</strong> (sexto ícono en el menú lateral, 🖼️)</p><h2 id="¿que-hace" tabindex="-1">¿Qué hace? <a class="header-anchor" href="#¿que-hace" aria-label="Permalink to &quot;¿Qué hace?&quot;">​</a></h2><p>Permite seleccionar <strong>variantes de diseño</strong> para las secciones que las soportan:</p><h3 id="variantes-disponibles-por-seccion" tabindex="-1">Variantes disponibles por sección <a class="header-anchor" href="#variantes-disponibles-por-seccion" aria-label="Permalink to &quot;Variantes disponibles por sección&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Sección</th><th>Variantes</th><th>Descripción</th></tr></thead><tbody><tr><td><strong>Hero</strong></td><td><code>fullscreen</code>, <code>gradient</code>, <code>split</code></td><td>Fullscreen: imagen de fondo completa. Gradient: degradado de color. Split: 50/50 texto e imagen.</td></tr><tr><td><strong>Productos</strong></td><td><code>grid3</code></td><td>Grid de 3 columnas (por defecto)</td></tr><tr><td><strong>Servicios</strong></td><td><code>cards</code>, <code>spotlight</code></td><td>Cards: tarjetas estándar. Spotlight: diseño con más énfasis.</td></tr><tr><td><strong>Acerca de</strong></td><td><code>split</code></td><td>Imagen izquierda + texto derecha</td></tr><tr><td><strong>FAQ</strong></td><td><code>accordion</code></td><td>Formato de preguntas colapsables</td></tr><tr><td><strong>CTA</strong></td><td><code>centered</code></td><td>Banda centrada con fondo de color primario</td></tr><tr><td><strong>Footer</strong></td><td><code>simple</code>, <code>v2</code></td><td>Simple: básico. V2: diseño alternativo con más secciones</td></tr></tbody></table><h3 id="efectos-visuales" tabindex="-1">Efectos visuales <a class="header-anchor" href="#efectos-visuales" aria-label="Permalink to &quot;Efectos visuales&quot;">​</a></h3><p>El tab también permite configurar efectos como:</p><ul><li>Espaciado entre secciones</li><li>Bordes y separadores</li><li>Animaciones de entrada (si están habilitadas)</li></ul><h2 id="¿que-no-hace" tabindex="-1">¿Qué NO hace? <a class="header-anchor" href="#¿que-no-hace" aria-label="Permalink to &quot;¿Qué NO hace?&quot;">​</a></h2><ul><li>No cambia los colores — eso se hace en <strong>Cómo Se Ve</strong></li><li>No agrega contenido — eso se hace en <strong>Tu Información</strong> y <strong>Qué Vendes</strong></li><li>No permite CSS personalizado</li><li>No tiene preview en tiempo real dentro del panel — abre tu landing para ver los cambios</li></ul><h2 id="disponibilidad-por-plan" tabindex="-1">Disponibilidad por plan <a class="header-anchor" href="#disponibilidad-por-plan" aria-label="Permalink to &quot;Disponibilidad por plan&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Característica</th><th>Oportunidad</th><th>Crecimiento</th><th>Visión</th></tr></thead><tbody><tr><td>Variantes Hero</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Variantes Servicios</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Variantes Footer</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Variantes Acerca de</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>Variantes FAQ</td><td>❌</td><td>❌</td><td>✅</td></tr><tr><td>Efectos visuales</td><td>✅</td><td>✅</td><td>✅</td></tr></tbody></table><h2 id="ejemplo-practico" tabindex="-1">Ejemplo práctico <a class="header-anchor" href="#ejemplo-practico" aria-label="Permalink to &quot;Ejemplo práctico&quot;">​</a></h2><h3 id="caso-fotografo-lens-pro-en-maracaibo" tabindex="-1">Caso: Fotógrafo &quot;Lens Pro&quot; en Maracaibo <a class="header-anchor" href="#caso-fotografo-lens-pro-en-maracaibo" aria-label="Permalink to &quot;Caso: Fotógrafo &quot;Lens Pro&quot; en Maracaibo&quot;">​</a></h3><p>Miguel tiene un estudio de fotografía con plan Crecimiento. Va a <strong>Visual</strong>:</p><ol><li>Cambia el <strong>Hero</strong> de <code>fullscreen</code> a <code>split</code> — ahora su foto de portada ocupa la mitad derecha y el texto la mitad izquierda</li><li>Cambia los <strong>Servicios</strong> de <code>cards</code> a <code>spotlight</code> — sus servicios se ven más llamativos</li><li>Cierra el panel → su landing tiene un aspecto completamente renovado sin cambiar ni una letra</li></ol><h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/studio/seccion-diseno.html">Cómo Se Ve — Diseño</a> — Cambia los colores con paletas</li><li><a href="/studio/hero-y-banner.html">Hero y banner</a> — La foto principal y variantes del hero</li><li><a href="/studio/panel-administracion.html">Panel de administración</a> — Los 7 tabs del panel</li></ul>',22)])])}const m=t(r,[["render",i]]);export{p as __pageData,m as default};
